import React, { useState } from 'react';
import { ApiConnection, ApiVariable, ApiArgument, ApiTrigger, DataConnection } from '../../types';

// API Templates for common use cases
const apiTemplates = {
    'generic-get': {
        name: 'Generic GET Request',
        description: 'Basic GET request for retrieving data',
        url: 'https://api.example.com/data',
        method: 'GET',
        headers: {
            'Accept': 'application/json',
            'Content-Type': 'application/json'
        },
        params: {},
        arguments: [
            {
                id: 'arg-1',
                name: 'id',
                type: 'static',
                value: '1',
                description: 'Resource ID to fetch'
            }
        ],
        trigger: {
            type: 'cyclic',
            interval: 30000
        },
        sampleResponse: `{
  "id": 1,
  "name": "Sample Data",
  "value": 42,
  "status": "active",
  "timestamp": "2025-10-03T10:00:00Z"
}`,
        variables: [
            { id: 'var-1', name: 'dataValue', jsonPath: 'value', type: 'number', description: 'Main data value' },
            { id: 'var-2', name: 'dataStatus', jsonPath: 'status', type: 'string', description: 'Current status' }
        ]
    },
    'generic-post': {
        name: 'Generic POST Request',
        description: 'POST request for creating/sending data',
        url: 'https://api.example.com/data',
        method: 'POST',
        headers: {
            'Accept': 'application/json',
            'Content-Type': 'application/json'
        },
        params: {},
        arguments: [
            {
                id: 'arg-1',
                name: 'name',
                type: 'variable',
                value: 'userName',
                description: 'Name from global variable'
            },
            {
                id: 'arg-2',
                name: 'value',
                type: 'static',
                value: '100',
                description: 'Static value to send'
            }
        ],
        trigger: {
            type: 'conditional',
            condition: {
                variable: 'sendData',
                operator: '==',
                value: true
            }
        },
        sampleResponse: `{
  "success": true,
  "id": 123,
  "message": "Data created successfully",
  "timestamp": "2025-10-03T10:00:00Z"
}`,
        variables: [
            { id: 'var-1', name: 'postSuccess', jsonPath: 'success', type: 'boolean', description: 'Request success status' },
            { id: 'var-2', name: 'newId', jsonPath: 'id', type: 'number', description: 'ID of created resource' }
        ]
    },
    'generic-put': {
        name: 'Generic PUT Request',
        description: 'PUT request for updating existing data',
        url: 'https://api.example.com/data',
        method: 'PUT',
        headers: {
            'Accept': 'application/json',
            'Content-Type': 'application/json'
        },
        params: {},
        arguments: [
            {
                id: 'arg-1',
                name: 'id',
                type: 'variable',
                value: 'recordId',
                description: 'ID of record to update'
            },
            {
                id: 'arg-2',
                name: 'status',
                type: 'static',
                value: 'updated',
                description: 'New status value'
            }
        ],
        trigger: {
            type: 'conditional',
            condition: {
                variable: 'updateTrigger',
                operator: '==',
                value: true
            }
        },
        sampleResponse: `{
  "success": true,
  "updated": true,
  "id": 123,
  "message": "Data updated successfully"
}`,
        variables: [
            { id: 'var-1', name: 'updateSuccess', jsonPath: 'success', type: 'boolean', description: 'Update success status' },
            { id: 'var-2', name: 'updatedId', jsonPath: 'id', type: 'number', description: 'ID of updated resource' }
        ]
    },
    's7-read': {
        name: 'S7 PLC Read Variables',
        description: 'Read variables from Siemens S7 PLC using HTTP GET',
        url: 'http://192.168.0.1/lhttp/read',
        method: 'GET',
        headers: {
            'Accept': 'application/json',
            'Authorization': 'Basic RXZlcnlib2R5Og=='
        },
        params: {
            'var': 'DB1.DBD0,DB1.DBD4,DB1.DBX8.0',
            'format': 'json'
        },
        arguments: [
            {
                id: 'arg-1',
                name: 'var',
                type: 'static',
                value: 'DB1.DBD0,DB1.DBD4,DB1.DBX8.0',
                description: 'Variables to read (comma-separated, e.g. DB1.DBD0,DB1.DBX8.0)'
            },
            {
                id: 'arg-2',
                name: 'format',
                type: 'static',
                value: 'json',
                description: 'Response format (json/xml)'
            }
        ],
        trigger: {
            type: 'cyclic',
            interval: 1000
        },
        sampleResponse: `{
  "variables": {
    "DB1.DBD0": {
      "value": 25.5,
      "quality": "good",
      "timestamp": "2025-10-07T10:00:00Z"
    },
    "DB1.DBD4": {
      "value": 1200,
      "quality": "good",
      "timestamp": "2025-10-07T10:00:00Z"
    },
    "DB1.DBX8.0": {
      "value": true,
      "quality": "good",
      "timestamp": "2025-10-07T10:00:00Z"
    }
  }
}`,
        variables: [
            { id: 'var-1', name: 'temperature', jsonPath: 'actualResponse.variables["DB1.DBD0"].value', type: 'number', description: 'Temperature value' },
            { id: 'var-2', name: 'pressure', jsonPath: 'actualResponse.variables["DB1.DBD4"].value', type: 'number', description: 'Pressure value' },
            { id: 'var-3', name: 'motorStatus', jsonPath: 'actualResponse.variables["DB1.DBX8.0"].value', type: 'boolean', description: 'Motor status' }
        ]
    },
    's7-write': {
        name: 'S7 PLC Write Variables',
        description: 'Write variables to Siemens S7 PLC using HTTP PUT',
        url: 'http://192.168.0.1/lhttp/write',
        method: 'PUT',
        headers: {
            'Accept': 'application/json',
            'Content-Type': 'application/x-www-form-urlencoded',
            'Authorization': 'Basic RXZlcnlib2R5Og=='
        },
        params: {},
        body: 'DB1.DBD0=30.5&DB1.DBX8.0=true',
        arguments: [
            {
                id: 'arg-1',
                name: 'DB1.DBD0',
                type: 'variable',
                value: 'setpointTemp',
                description: 'Temperature setpoint value'
            },
            {
                id: 'arg-2',
                name: 'DB1.DBX8.0',
                type: 'variable',
                value: 'motorStart',
                description: 'Motor start command'
            }
        ],
        trigger: {
            type: 'conditional',
            condition: {
                variable: 'writeToPlc',
                operator: '==',
                value: true
            }
        },
        sampleResponse: `{
  "success": true,
  "written": {
    "DB1.DBD0": {
      "success": true,
      "value": 30.5
    },
    "DB1.DBX8.0": {
      "success": true,
      "value": true
    }
  },
  "timestamp": "2025-10-07T10:00:00Z"
}`,
        variables: [
            { id: 'var-1', name: 'writeSuccess', jsonPath: 'actualResponse.success', type: 'boolean', description: 'Write operation success' },
            { id: 'var-2', name: 'writtenCount', jsonPath: 'actualResponse.written', type: 'object', description: 'Written variables details' }
        ]
    }
};

interface DataConnectionsProps {
    dataConnections: DataConnection;
    onDataConnectionsChange: (connections: DataConnection) => void;
}

const DataConnections: React.FC<DataConnectionsProps> = ({
    dataConnections,
    onDataConnectionsChange
}) => {
    const [activeConnection, setActiveConnection] = useState<string | null>(null);
    const [newConnectionName, setNewConnectionName] = useState('');
    const [showAddConnection, setShowAddConnection] = useState(false);
    const [expandedResponse, setExpandedResponse] = useState<boolean>(false);
    const [testingConnection, setTestingConnection] = useState<string | null>(null);
    const [testResults, setTestResults] = useState<Record<string, any>>({});

    const handleAddConnection = () => {
        if (!newConnectionName.trim()) return;

        const newConnection: ApiConnection = {
            id: `api-${Date.now()}`,
            name: newConnectionName.trim(),
            url: '',
            method: 'GET',
            headers: {},
            params: {},
            arguments: [],
            trigger: {
                type: 'cyclic',
                interval: 5000
            },
            sampleResponse: '',
            variables: [],
            enabled: true
        };

        onDataConnectionsChange({
            ...dataConnections,
            apiConnections: [...dataConnections.apiConnections, newConnection]
        });

        setNewConnectionName('');
        setShowAddConnection(false);
        setActiveConnection(newConnection.id);
    };

    const handleDeleteConnection = (connectionId: string) => {
        onDataConnectionsChange({
            ...dataConnections,
            apiConnections: dataConnections.apiConnections.filter(conn => conn.id !== connectionId)
        });
        if (activeConnection === connectionId) {
            setActiveConnection(null);
        }
    };

    const handleUpdateConnection = (connectionId: string, updates: Partial<ApiConnection>) => {
        onDataConnectionsChange({
            ...dataConnections,
            apiConnections: dataConnections.apiConnections.map(conn =>
                conn.id === connectionId ? { ...conn, ...updates } : conn
            )
        });
    };

    const handleAddVariable = (connectionId: string) => {
        const newVariable: ApiVariable = {
            id: `var-${Date.now()}`,
            name: '',
            jsonPath: '',
            type: 'string',
            description: ''
        };

        const connection = dataConnections.apiConnections.find(c => c.id === connectionId);
        if (connection) {
            handleUpdateConnection(connectionId, {
                variables: [...connection.variables, newVariable]
            });
        }
    };

    const handleUpdateVariable = (connectionId: string, variableId: string, updates: Partial<ApiVariable>) => {
        const connection = dataConnections.apiConnections.find(c => c.id === connectionId);
        if (connection) {
            handleUpdateConnection(connectionId, {
                variables: connection.variables.map(variable =>
                    variable.id === variableId ? { ...variable, ...updates } : variable
                )
            });
        }
    };

    const handleDeleteVariable = (connectionId: string, variableId: string) => {
        const connection = dataConnections.apiConnections.find(c => c.id === connectionId);
        if (connection) {
            handleUpdateConnection(connectionId, {
                variables: connection.variables.filter(variable => variable.id !== variableId)
            });
        }
    };

    const handleTestConnection = async (connectionId: string) => {
        const connection = dataConnections.apiConnections.find(c => c.id === connectionId);
        if (!connection) return;

        setTestingConnection(connectionId);
        
        // Declare variables in broader scope for error reporting
        let url = connection.url;
        let requestBody: any = null;
        
        try {
            // Build the complete URL with parameters and arguments
            const urlParams = new URLSearchParams();
            
            // Add URL parameters
            Object.entries(connection.params).forEach(([key, value]) => {
                if (value) urlParams.append(key, value);
            });
            
            // Add arguments as query parameters for GET requests or prepare body for POST/PUT
            if (connection.method === 'GET') {
                connection.arguments.forEach(arg => {
                    if (arg.type === 'static') {
                        urlParams.append(arg.name, arg.value);
                    } else if (arg.type === 'variable') {
                        // For testing, use placeholder values for variables
                        const variableValue = dataConnections.globalVariables[arg.value] || `[${arg.value}]`;
                        urlParams.append(arg.name, String(variableValue));
                    }
                });
            } else {
                // For POST/PUT, check if connection has a predefined body (like JSON-RPC)
                if (connection.body) {
                    // Clone the body structure and inject argument values
                    let body = JSON.parse(JSON.stringify(connection.body));
                    
                    connection.arguments.forEach(arg => {
                        let value = arg.value;
                        if (arg.type === 'variable') {
                            value = dataConnections.globalVariables[arg.value] || `[${arg.value}]`;
                        }
                        
                        // For JSON-RPC, inject values into params
                        if (body.params && body.params.hasOwnProperty(arg.name)) {
                            body.params[arg.name] = value;
                        } else if (arg.name === 'requests' && Array.isArray(body.params?.requests)) {
                            // Handle bulk requests
                            try {
                                body.params.requests = JSON.parse(value);
                            } catch {
                                // Keep original if parsing fails
                            }
                        }
                    });
                    
                    requestBody = JSON.stringify(body);
                } else {
                    // Check if connection has predefined body string (for form-encoded data)
                    if (typeof connection.body === 'string') {
                        // Use the predefined body and replace argument placeholders
                        requestBody = connection.body;
                        connection.arguments.forEach(arg => {
                            let value = arg.value;
                            if (arg.type === 'variable') {
                                value = dataConnections.globalVariables[arg.value] || `[${arg.value}]`;
                            }
                            // Replace in body string
                            const regex = new RegExp(`${arg.name}=[^&]*`, 'g');
                            requestBody = requestBody.replace(regex, `${arg.name}=${encodeURIComponent(value)}`);
                        });
                    } else {
                        // Traditional JSON body
                        const body: any = {};
                        connection.arguments.forEach(arg => {
                            if (arg.type === 'static') {
                                body[arg.name] = arg.value;
                            } else if (arg.type === 'variable') {
                                body[arg.name] = dataConnections.globalVariables[arg.value] || `[${arg.value}]`;
                            }
                        });
                        requestBody = JSON.stringify(body);
                    }
                }
            }
            
            // Append query parameters to URL
            if (urlParams.toString()) {
                url += (url.includes('?') ? '&' : '?') + urlParams.toString();
            }

            const response = await fetch(url, {
                method: connection.method,
                headers: {
                    ...connection.headers,
                    // Only add JSON content-type if not already specified and body is JSON
                    ...(requestBody && !connection.headers['Content-Type'] && typeof connection.body !== 'string' && { 'Content-Type': 'application/json' })
                },
                body: requestBody
            });

            const responseText = await response.text();
            let responseData: any;
            
            try {
                responseData = JSON.parse(responseText);
            } catch {
                responseData = { error: 'Response is not valid JSON', rawResponse: responseText };
            }

            // Create detailed response with request/response info
            const detailedResponse = {
                actualResponse: responseData,
                requestDetails: {
                    url: url,
                    method: connection.method,
                    headers: connection.headers,
                    body: requestBody ? JSON.parse(requestBody) : null
                },
                responseDetails: {
                    status: response.status,
                    statusText: response.statusText,
                    ok: response.ok,
                    headers: Object.fromEntries(Array.from(response.headers.entries())),
                    timestamp: new Date().toISOString()
                }
            };
            
            const formattedResponse = JSON.stringify(detailedResponse, null, 2);
            handleUpdateConnection(connectionId, { sampleResponse: formattedResponse });
            
            // Store test results
            setTestResults(prev => ({
                ...prev,
                [connectionId]: {
                    success: response.ok,
                    status: response.status,
                    statusText: response.statusText,
                    data: responseData,
                    timestamp: new Date().toISOString()
                }
            }));

        } catch (error) {
            console.error('API Test Error:', error);
            
            // Create detailed error response with debugging info
            const errorResponse = {
                error: 'Failed to connect to API',
                message: error instanceof Error ? error.message : 'Unknown error',
                requestDetails: {
                    url: url,
                    method: connection.method,
                    headers: connection.headers,
                    body: requestBody ? JSON.parse(requestBody) : null
                },
                troubleshooting: {
                    commonIssues: [
                        "Check if PLC IP address is correct and reachable",
                        "Verify PLC Web API is enabled in TIA Portal",
                        "Check if HTTPS certificate is trusted (try HTTP if available)",
                        "Verify authentication credentials",
                        "Check if CORS is blocking the request (browser console)"
                    ]
                },
                timestamp: new Date().toISOString()
            };
            
            const formattedResponse = JSON.stringify(errorResponse, null, 2);
            handleUpdateConnection(connectionId, { sampleResponse: formattedResponse });
            
            setTestResults(prev => ({
                ...prev,
                [connectionId]: {
                    success: false,
                    error: error instanceof Error ? error.message : 'Unknown error',
                    timestamp: new Date().toISOString()
                }
            }));
        } finally {
            setTestingConnection(null);
        }
    };

    const activeConnectionData = dataConnections.apiConnections.find(c => c.id === activeConnection);

    return (
        <div style={{ padding: '20px', height: '100%', overflow: 'auto' }}>
            <div style={{ marginBottom: '20px' }}>
                <h3 style={{ margin: '0 0 15px 0', color: '#343a40' }}>Data Connections</h3>
                <p style={{ fontSize: '12px', color: '#6c757d', margin: '0 0 15px 0' }}>
                    Create API connections and define global variables for your windows
                </p>
            </div>

            <div style={{ display: 'grid', gridTemplateColumns: '200px 1fr', gap: '20px', height: 'calc(100% - 80px)' }}>
                {/* Left Panel - Connections List */}
                <div style={{ backgroundColor: '#f8f9fa', borderRadius: '5px', padding: '15px', overflow: 'auto' }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '15px' }}>
                        <h4 style={{ margin: 0, fontSize: '14px' }}>Connections</h4>
                        <button
                            onClick={() => setShowAddConnection(!showAddConnection)}
                            style={{
                                padding: '4px 8px',
                                fontSize: '11px',
                                backgroundColor: '#28a745',
                                color: 'white',
                                border: 'none',
                                borderRadius: '3px',
                                cursor: 'pointer'
                            }}
                        >
                            + Add
                        </button>
                    </div>

                    {showAddConnection && (
                        <div style={{ marginBottom: '15px', padding: '10px', backgroundColor: 'white', borderRadius: '3px' }}>
                            <input
                                type="text"
                                placeholder="Connection name"
                                value={newConnectionName}
                                onChange={(e) => setNewConnectionName(e.target.value)}
                                style={{
                                    width: '100%',
                                    padding: '5px',
                                    fontSize: '11px',
                                    border: '1px solid #ced4da',
                                    borderRadius: '3px',
                                    marginBottom: '8px'
                                }}
                            />
                            <div style={{ display: 'flex', gap: '5px' }}>
                                <button
                                    onClick={handleAddConnection}
                                    style={{
                                        padding: '4px 8px',
                                        fontSize: '10px',
                                        backgroundColor: '#007bff',
                                        color: 'white',
                                        border: 'none',
                                        borderRadius: '2px',
                                        cursor: 'pointer'
                                    }}
                                >
                                    Create
                                </button>
                                <button
                                    onClick={() => setShowAddConnection(false)}
                                    style={{
                                        padding: '4px 8px',
                                        fontSize: '10px',
                                        backgroundColor: '#6c757d',
                                        color: 'white',
                                        border: 'none',
                                        borderRadius: '2px',
                                        cursor: 'pointer'
                                    }}
                                >
                                    Cancel
                                </button>
                            </div>
                        </div>
                    )}

                    {/* Templates Section */}
                    <div style={{ marginBottom: '20px' }}>
                        <h5 style={{ fontSize: '12px', margin: '0 0 10px 0', color: '#495057' }}>Templates</h5>
                        <div style={{ display: 'flex', flexDirection: 'column', gap: '5px' }}>
                            {Object.entries(apiTemplates).map(([key, template]) => (
                                <button
                                    key={key}
                                    onClick={() => {
                                        const newConnection: ApiConnection = {
                                            id: `api-${Date.now()}`,
                                            name: template.name,  
                                            url: template.url,
                                            // @ts-ignore
                                            method: template.method,
                                            headers: template.headers,
                                            params: template.params,
                                            // @ts-ignore
                                            body: template.body,
                                            // @ts-ignore
                                            arguments: template.arguments.map(arg => ({ ...arg, id: `arg-${Date.now()}-${Math.random()}` })),
                                            // @ts-ignore
                                            trigger: template.trigger,
                                            sampleResponse: template.sampleResponse,
                                            // @ts-ignore
                                            variables: template.variables.map(variable => ({ ...variable, id: `var-${Date.now()}-${Math.random()}` })),
                                            enabled: true
                                        };
                                        
                                        onDataConnectionsChange({
                                            ...dataConnections,
                                            apiConnections: [...dataConnections.apiConnections, newConnection]
                                        });
                                        setActiveConnection(newConnection.id);
                                    }}
                                    style={{
                                        padding: '6px 8px',
                                        fontSize: '10px',
                                        backgroundColor: 'white',
                                        border: '1px solid #dee2e6',
                                        borderRadius: '3px',
                                        cursor: 'pointer',
                                        textAlign: 'left'
                                    }}
                                >
                                    {template.name}
                                </button>
                            ))}
                        </div>
                    </div>

                    {/* Connections List */}
                    <div>
                        {dataConnections.apiConnections.map(connection => (
                            <div
                                key={connection.id}
                                style={{
                                    padding: '8px',
                                    backgroundColor: activeConnection === connection.id ? '#007bff' : 'white',
                                    color: activeConnection === connection.id ? 'white' : 'black',
                                    borderRadius: '3px',
                                    cursor: 'pointer',
                                    marginBottom: '5px',
                                    fontSize: '11px',
                                    display: 'flex',
                                    justifyContent: 'space-between',
                                    alignItems: 'center'
                                }}
                                onClick={() => setActiveConnection(connection.id)}
                            >
                                <span>{connection.name}</span>
                                <button
                                    onClick={(e) => {
                                        e.stopPropagation();
                                        handleDeleteConnection(connection.id);
                                    }}
                                    style={{
                                        padding: '2px 5px',
                                        fontSize: '10px',
                                        backgroundColor: 'transparent',
                                        color: activeConnection === connection.id ? 'white' : '#dc3545',
                                        border: 'none',
                                        cursor: 'pointer'
                                    }}
                                >
                                    ×
                                </button>
                            </div>
                        ))}
                    </div>
                </div>

                {/* Right Panel - Connection Details */}
                <div style={{ backgroundColor: 'white', borderRadius: '5px', padding: '20px', overflow: 'auto' }}>
                    {activeConnectionData ? (
                        <div>
                            <h4 style={{ margin: '0 0 20px 0', fontSize: '16px' }}>{activeConnectionData.name}</h4>
                            
                            {/* Basic Settings */}
                            <div style={{ marginBottom: '15px' }}>
                                <label style={{ fontSize: '12px', fontWeight: 'bold', display: 'block', marginBottom: '5px' }}>
                                    URL:
                                </label>
                                <input
                                    type="text"
                                    value={activeConnectionData.url}
                                    onChange={(e) => handleUpdateConnection(activeConnectionData.id, { url: e.target.value })}
                                    style={{
                                        width: '100%',
                                        padding: '6px',
                                        fontSize: '12px',
                                        border: '1px solid #ced4da',
                                        borderRadius: '3px'
                                    }}
                                />
                            </div>

                            <div style={{ marginBottom: '15px' }}>
                                <label style={{ fontSize: '12px', fontWeight: 'bold', display: 'block', marginBottom: '5px' }}>
                                    Method:
                                </label>
                                <select
                                    value={activeConnectionData.method}
                                    onChange={(e) => handleUpdateConnection(activeConnectionData.id, { method: e.target.value as any })}
                                    style={{
                                        padding: '6px',
                                        fontSize: '12px',
                                        border: '1px solid #ced4da',
                                        borderRadius: '3px'
                                    }}
                                >
                                    <option value="GET">GET</option>
                                    <option value="POST">POST</option>
                                    <option value="PUT">PUT</option>
                                    <option value="DELETE">DELETE</option>
                                </select>
                            </div>

                            {/* Headers */}
                            <div style={{ marginBottom: '15px' }}>
                                <label style={{ fontSize: '12px', fontWeight: 'bold', display: 'block', marginBottom: '5px' }}>
                                    Headers (JSON):
                                </label>
                                <textarea
                                    value={JSON.stringify(activeConnectionData.headers, null, 2)}
                                    onChange={(e) => {
                                        try {
                                            const headers = JSON.parse(e.target.value);
                                            handleUpdateConnection(activeConnectionData.id, { headers });
                                        } catch {
                                            // Invalid JSON, don't update
                                        }
                                    }}
                                    style={{
                                        width: '100%',
                                        height: '80px',
                                        padding: '6px',
                                        fontSize: '11px',
                                        fontFamily: 'monospace',
                                        border: '1px solid #ced4da',
                                        borderRadius: '3px',
                                        resize: 'vertical'
                                    }}
                                />
                            </div>

                            {/* Parameters */}
                            <div style={{ marginBottom: '15px' }}>
                                <label style={{ fontSize: '12px', fontWeight: 'bold', display: 'block', marginBottom: '5px' }}>
                                    Parameters (JSON):
                                </label>
                                <textarea
                                    value={JSON.stringify(activeConnectionData.params, null, 2)}
                                    onChange={(e) => {
                                        try {
                                            const params = JSON.parse(e.target.value);
                                            handleUpdateConnection(activeConnectionData.id, { params });
                                        } catch {
                                            // Invalid JSON, don't update
                                        }
                                    }}
                                    style={{
                                        width: '100%',
                                        height: '60px',
                                        padding: '6px',
                                        fontSize: '11px',
                                        fontFamily: 'monospace',
                                        border: '1px solid #ced4da',
                                        borderRadius: '3px',
                                        resize: 'vertical'
                                    }}
                                />
                            </div>

                            {/* Trigger */}
                            <div style={{ marginBottom: '15px' }}>
                                <label style={{ fontSize: '12px', fontWeight: 'bold', display: 'block', marginBottom: '8px' }}>
                                    Trigger:
                                </label>
                                <div style={{ display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '8px' }}>
                                    <select
                                        value={activeConnectionData.trigger.type}
                                        onChange={(e) => {
                                            const triggerType = e.target.value as any;
                                            const newTrigger = triggerType === 'cyclic' 
                                                ? { type: triggerType, interval: 5000 }
                                                : { type: 'conditional', condition: { variable: '', operator: '==', value: '' } };
                                            handleUpdateConnection(activeConnectionData.id, { trigger: newTrigger });
                                        }}
                                        style={{
                                            padding: '4px',
                                            fontSize: '11px',
                                            border: '1px solid #ced4da',
                                            borderRadius: '3px'
                                        }}
                                    >
                                        <option value="cyclic">Cyclic</option>
                                        <option value="conditional">Conditional</option>
                                    </select>
                                    
                                    {activeConnectionData.trigger.type === 'cyclic' && (
                                        <div style={{ display: 'flex', alignItems: 'center', gap: '5px' }}>
                                            <span style={{ fontSize: '11px' }}>Every</span>
                                            <input
                                                type="number"
                                                value={activeConnectionData.trigger.interval || 5000}
                                                onChange={(e) => {
                                                    handleUpdateConnection(activeConnectionData.id, {
                                                        trigger: { ...activeConnectionData.trigger, interval: parseInt(e.target.value) }
                                                    });
                                                }}
                                                style={{
                                                    width: '80px',
                                                    padding: '4px',
                                                    fontSize: '11px',
                                                    border: '1px solid #ced4da',
                                                    borderRadius: '3px'
                                                }}
                                            />
                                            <span style={{ fontSize: '11px' }}>ms</span>
                                        </div>
                                    )}
                                </div>
                                
                                {activeConnectionData.trigger.type === 'conditional' && (
                                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 80px 1fr', gap: '5px', alignItems: 'center' }}>
                                        <input
                                            type="text"
                                            placeholder="Variable name"
                                            value={activeConnectionData.trigger.condition?.variable || ''}
                                            onChange={(e) => {
                                                // @ts-ignore
                                                const condition = activeConnectionData.trigger.condition || { variable: '', operator: '==', value: '' };
                                                handleUpdateConnection(activeConnectionData.id, {
                                                    trigger: {
                                                        ...activeConnectionData.trigger,
                                                        // @ts-ignore
                                                        condition: { ...condition, variable: e.target.value }
                                                    }
                                                });
                                            }}
                                            style={{
                                                padding: '4px',
                                                fontSize: '11px',
                                                border: '1px solid #ced4da',
                                                borderRadius: '3px'
                                            }}
                                        />
                                        <select
                                            value={activeConnectionData.trigger.condition?.operator || '=='}
                                            onChange={(e) => {
                                                // @ts-ignore
                                                const condition = activeConnectionData.trigger.condition || { variable: '', operator: '==', value: '' };
                                                handleUpdateConnection(activeConnectionData.id, {
                                                    trigger: {
                                                        ...activeConnectionData.trigger,
                                                        // @ts-ignore
                                                        condition: { ...condition, operator: e.target.value }
                                                    }
                                                });
                                            }}
                                            style={{
                                                padding: '4px',
                                                fontSize: '11px',
                                                border: '1px solid #ced4da',
                                                borderRadius: '3px'
                                            }}
                                        >
                                            <option value="==">=</option>
                                            <option value="!=">≠</option>
                                            <option value=">">&gt;</option>
                                            <option value="<">&lt;</option>
                                            <option value=">=">&gt;=</option>
                                            <option value="<=">&lt;=</option>
                                        </select>
                                        <input
                                            type="text"
                                            placeholder="Value"
                                            value={String(activeConnectionData.trigger.condition?.value || '')}
                                            onChange={(e) => {
                                                // @ts-ignore
                                                const condition = activeConnectionData.trigger.condition || { variable: '', operator: '==', value: '' };
                                                handleUpdateConnection(activeConnectionData.id, {
                                                    trigger: {
                                                        ...activeConnectionData.trigger,
                                                        condition: { ...condition, value: e.target.value }
                                                    }
                                                });
                                            }}
                                            style={{
                                                padding: '4px',
                                                fontSize: '11px',
                                                border: '1px solid #ced4da',
                                                borderRadius: '3px'
                                            }}
                                        />
                                    </div>
                                )}
                            </div>

                            {/* API Arguments */}
                            <div style={{ marginBottom: '15px' }}>
                                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '8px' }}>
                                    <label style={{ fontSize: '12px', fontWeight: 'bold' }}>
                                        API Arguments:
                                    </label>
                                    <button
                                        onClick={() => {
                                            const newArg: ApiArgument = {
                                                id: `arg-${Date.now()}`,
                                                name: '',
                                                type: 'static',
                                                value: '',
                                                description: ''
                                            };
                                            handleUpdateConnection(activeConnectionData.id, {
                                                arguments: [...activeConnectionData.arguments, newArg]
                                            });
                                        }}
                                        style={{
                                            padding: '2px 6px',
                                            fontSize: '10px',
                                            backgroundColor: '#28a745',
                                            color: 'white',
                                            border: 'none',
                                            borderRadius: '2px',
                                            cursor: 'pointer'
                                        }}
                                    >
                                        + Add Argument
                                    </button>
                                </div>

                                {activeConnectionData.arguments.map((arg, index) => (
                                    <div key={arg.id} style={{
                                        padding: '8px',
                                        backgroundColor: '#f8f9fa',
                                        borderRadius: '4px',
                                        marginBottom: '5px',
                                        border: '1px solid #dee2e6'
                                    }}>
                                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 80px 1fr 20px', gap: '5px', alignItems: 'center' }}>
                                            <input
                                                type="text"
                                                placeholder="Argument name"
                                                value={arg.name}
                                                onChange={(e) => {
                                                    const newArgs = [...activeConnectionData.arguments];
                                                    newArgs[index] = { ...arg, name: e.target.value };
                                                    handleUpdateConnection(activeConnectionData.id, { arguments: newArgs });
                                                }}
                                                style={{
                                                    padding: '4px',
                                                    fontSize: '11px',
                                                    border: '1px solid #ced4da',
                                                    borderRadius: '3px'
                                                }}
                                            />
                                            <select
                                                value={arg.type}
                                                onChange={(e) => {
                                                    const newArgs = [...activeConnectionData.arguments];
                                                    // @ts-ignore
                                                    newArgs[index] = { ...arg, type: e.target.value };
                                                    handleUpdateConnection(activeConnectionData.id, { arguments: newArgs });
                                                }}
                                                style={{
                                                    padding: '4px',
                                                    fontSize: '11px',
                                                    border: '1px solid #ced4da',
                                                    borderRadius: '3px'
                                                }}
                                            >
                                                <option value="static">Static</option>
                                                <option value="variable">Variable</option>
                                            </select>
                                            <input
                                                type="text"
                                                placeholder={arg.type === 'static' ? "Static value" : "Variable name"}
                                                value={arg.value}
                                                onChange={(e) => {
                                                    const newArgs = [...activeConnectionData.arguments];
                                                    newArgs[index] = { ...arg, value: e.target.value };
                                                    handleUpdateConnection(activeConnectionData.id, { arguments: newArgs });
                                                }}
                                                style={{
                                                    padding: '4px',
                                                    fontSize: '11px',
                                                    border: '1px solid #ced4da',
                                                    borderRadius: '3px'
                                                }}
                                            />
                                            <button
                                                onClick={() => {
                                                    const newArgs = activeConnectionData.arguments.filter(a => a.id !== arg.id);
                                                    handleUpdateConnection(activeConnectionData.id, { arguments: newArgs });
                                                }}
                                                style={{
                                                    padding: '2px',
                                                    fontSize: '10px',
                                                    backgroundColor: '#dc3545',
                                                    color: 'white',
                                                    border: 'none',
                                                    borderRadius: '2px',
                                                    cursor: 'pointer',
                                                    width: '20px',
                                                    height: '20px'
                                                }}
                                                title="Delete argument"
                                            >
                                                ×
                                            </button>
                                        </div>
                                        {arg.description !== undefined && (
                                            <input
                                                type="text"
                                                placeholder="Description (optional)"
                                                value={arg.description}
                                                onChange={(e) => {
                                                    const newArgs = [...activeConnectionData.arguments];
                                                    newArgs[index] = { ...arg, description: e.target.value };
                                                    handleUpdateConnection(activeConnectionData.id, { arguments: newArgs });
                                                }}
                                                style={{
                                                    width: '100%',
                                                    padding: '4px',
                                                    fontSize: '11px',
                                                    border: '1px solid #ced4da',
                                                    borderRadius: '3px',
                                                    marginTop: '5px'
                                                }}
                                            />
                                        )}
                                    </div>
                                ))}
                            </div>

                            {/* Sample Response */}
                            <div style={{ marginBottom: '15px' }}>
                                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '5px' }}>
                                    <label style={{ fontSize: '12px', fontWeight: 'bold' }}>
                                        Sample Response (JSON):
                                    </label>
                                    <div style={{ display: 'flex', gap: '8px' }}>
                                        <button
                                            onClick={() => handleTestConnection(activeConnectionData.id)}
                                            disabled={testingConnection === activeConnectionData.id || !activeConnectionData.url}
                                            style={{
                                                padding: '4px 8px',
                                                fontSize: '10px',
                                                backgroundColor: testingConnection === activeConnectionData.id ? '#6c757d' : '#007bff',
                                                color: 'white',
                                                border: 'none',
                                                borderRadius: '3px',
                                                cursor: testingConnection === activeConnectionData.id || !activeConnectionData.url ? 'not-allowed' : 'pointer',
                                                display: 'flex',
                                                alignItems: 'center',
                                                gap: '4px'
                                            }}
                                        >
                                            {testingConnection === activeConnectionData.id ? (
                                                <>🔄 Testing...</>
                                            ) : (
                                                <>🧪 Test API</>
                                            )}
                                        </button>
                                        <button
                                            onClick={() => setExpandedResponse(!expandedResponse)}
                                            style={{
                                                padding: '4px 8px',
                                                fontSize: '10px',
                                                backgroundColor: '#28a745',
                                                color: 'white',
                                                border: 'none',
                                                borderRadius: '3px',
                                                cursor: 'pointer'
                                            }}
                                        >
                                            {expandedResponse ? '📐 Collapse' : '📏 Expand'}
                                        </button>
                                    </div>
                                </div>
                                
                                {/* Test Results */}
                                {testResults[activeConnectionData.id] && (
                                    <div style={{
                                        marginBottom: '8px',
                                        padding: '6px',
                                        fontSize: '10px',
                                        borderRadius: '3px',
                                        backgroundColor: testResults[activeConnectionData.id].success ? '#d4edda' : '#f8d7da',
                                        border: `1px solid ${testResults[activeConnectionData.id].success ? '#c3e6cb' : '#f5c6cb'}`,
                                        color: testResults[activeConnectionData.id].success ? '#155724' : '#721c24'
                                    }}>
                                        <strong>Last Test:</strong> {testResults[activeConnectionData.id].success ? 'Success' : 'Failed'} 
                                        {testResults[activeConnectionData.id].status && ` (${testResults[activeConnectionData.id].status})`}
                                        {testResults[activeConnectionData.id].error && ` - ${testResults[activeConnectionData.id].error}`}
                                        <br />
                                        <strong>Time:</strong> {new Date(testResults[activeConnectionData.id].timestamp).toLocaleString()}
                                    </div>
                                )}
                                
                                <textarea
                                    placeholder='{"name": "John", "age": 30, "items": [1, 2, 3]}'
                                    value={activeConnectionData.sampleResponse}
                                    onChange={(e) => handleUpdateConnection(activeConnectionData.id, { sampleResponse: e.target.value })}
                                    style={{
                                        width: '100%',
                                        height: expandedResponse ? '300px' : '80px',
                                        padding: '6px',
                                        fontSize: '11px',
                                        fontFamily: 'monospace',
                                        border: '1px solid #ced4da',
                                        borderRadius: '3px',
                                        resize: 'vertical',
                                        transition: 'height 0.3s ease'
                                    }}
                                />
                            </div>

                            {/* Variables */}
                            <div style={{ marginBottom: '15px' }}>
                                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '10px' }}>
                                    <label style={{ fontSize: '12px', fontWeight: 'bold' }}>Variables:</label>
                                    <button
                                        onClick={() => handleAddVariable(activeConnectionData.id)}
                                        style={{
                                            padding: '2px 6px',
                                            fontSize: '10px',
                                            backgroundColor: '#28a745',
                                            color: 'white',
                                            border: 'none',
                                            borderRadius: '3px',
                                            cursor: 'pointer'
                                        }}
                                    >
                                        + Add Variable
                                    </button>
                                </div>

                                {activeConnectionData.variables.map(variable => (
                                    <div key={variable.id} style={{
                                        padding: '8px',
                                        backgroundColor: 'white',
                                        border: '1px solid #dee2e6',
                                        borderRadius: '3px',
                                        marginBottom: '8px'
                                    }}>
                                        <div style={{ display: 'flex', gap: '8px', marginBottom: '8px' }}>
                                            <input
                                                type="text"
                                                placeholder="Variable name"
                                                value={variable.name}
                                                onChange={(e) => handleUpdateVariable(activeConnectionData.id, variable.id, { name: e.target.value })}
                                                style={{
                                                    flex: 1,
                                                    padding: '4px',
                                                    fontSize: '11px',
                                                    border: '1px solid #ced4da',
                                                    borderRadius: '2px'
                                                }}
                                            />
                                            <select
                                                value={variable.type}
                                                // @ts-ignore
                                                onChange={(e) => handleUpdateVariable(activeConnectionData.id, variable.id, { type: e.target.value })}
                                                style={{
                                                    padding: '4px',
                                                    fontSize: '11px',
                                                    border: '1px solid #ced4da',
                                                    borderRadius: '2px'
                                                }}
                                            >
                                                <option value="string">String</option>
                                                <option value="number">Number</option>
                                                <option value="boolean">Boolean</option>
                                                <option value="object">Object</option>
                                                <option value="array">Array</option>
                                            </select>
                                            <button
                                                onClick={() => handleDeleteVariable(activeConnectionData.id, variable.id)}
                                                style={{
                                                    padding: '2px 6px',
                                                    fontSize: '10px',
                                                    backgroundColor: '#dc3545',
                                                    color: 'white',
                                                    border: 'none',
                                                    borderRadius: '2px',
                                                    cursor: 'pointer'
                                                }}
                                            >
                                                ×
                                            </button>
                                        </div>
                                        <div style={{ display: 'flex', gap: '8px' }}>
                                            <input
                                                type="text"
                                                placeholder="JSON Path (e.g., data.items[0].name)"
                                                value={variable.jsonPath}
                                                onChange={(e) => handleUpdateVariable(activeConnectionData.id, variable.id, { jsonPath: e.target.value })}
                                                style={{
                                                    flex: 1,
                                                    padding: '4px',
                                                    fontSize: '11px',
                                                    border: '1px solid #ced4da',
                                                    borderRadius: '2px'
                                                }}
                                            />
                                        </div>
                                        {variable.description !== undefined && (
                                            <input
                                                type="text"
                                                placeholder="Description (optional)"
                                                value={variable.description}
                                                onChange={(e) => handleUpdateVariable(activeConnectionData.id, variable.id, { description: e.target.value })}
                                                style={{
                                                    width: '100%',
                                                    padding: '4px',
                                                    fontSize: '11px',
                                                    border: '1px solid #ced4da',
                                                    borderRadius: '2px',
                                                    marginTop: '8px'
                                                }}
                                            />
                                        )}
                                    </div>
                                ))}
                            </div>
                        </div>
                    ) : (
                        <div style={{ textAlign: 'center', color: '#6c757d', marginTop: '50px' }}>
                            <p>Select a connection from the left panel or create a new one</p>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

export default DataConnections;
